using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change #1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents still use "Discriminator", so keep the old name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change #2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|<key>", so preserve the old format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change #3: EF 9 removed support for HasIndex on Cosmos.
            // Cosmos DB does not support secondary indexes via EF; remove HasIndex call.
            // (was: entity.HasIndex(b => b.Name); — deleted)
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change #4: EF 9 uses sync-over-async by default for Cosmos,
    // which throws on synchronous calls. Use async APIs (see SyncJob.cs).
}

